def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 7):
            base = (ratio ** j) / j
            if j % 2 == 0:
                base *= 1.1
            else:
                base *= 0.9
            if base < 0.05:
                base *= 0.5
            elif base > 0.3:
                base *= 1.3
            score += base
        if capacity > item * 3:
            for k in range(1, 4):
                score -= (k * 0.05)
        elif capacity < item * 1.2:
            for k in range(1, 3):
                score += (k * 0.1)
        if score < 0:
            score = 0
        if ratio > 0.8:
            score *= 1.5
            if capacity % 2 == 0:
                score += 0.2
            else:
                score -= 0.1
        if score > 2:
            score = 2
        priorities[i] = score
    max_priority = np.max(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 15
    return priorities
